fieldUpdates.formula:
IF( (Tipo_de_Movimiento__c = "NCT" || Tipo_de_Movimiento__c = "NDT" || (Tipo_de_Movimiento__c = "APSE" && Moneda__c = "ARS" && TEXT( Oportunidad__r.Divisa_Comprobante__c ) <> "ARS") ),0,
        IF( Moneda__c = "ARS" && TEXT( Oportunidad__r.Divisa_Comprobante__c ) <> "ARS", Importe__c * Multiplicador__c / Tipo_de_Cambio__c,
                Importe__c * Multiplicador__c
        )
)
